-- =============================================================================
-- 0013_seed_unidasul_opportunities.sql — Tenant Unidasul + admin + 64 opps (Workshop I)
-- =============================================================================
-- Cria, para o cliente piloto UNIDASUL:
--   • Tenant `unidasul` (UUID fixo 55551da5-...)
--   • Auth user admin.unidasul@pswdigital.com.br / 0123456789 (UUID fixo bbbbbbbb-...)
--   • Identidade email no auth.identities (necessário para login funcionar)
--   • Profile vinculado é criado AUTOMATICAMENTE pelo trigger handle_new_user
--     (0001_init.sql) — ele lê tenant_id do raw_app_meta_data
--   • As 64 oportunidades reais do Workshop I (fonte do const DATA do
--     _giba_wsi-dashboard.html), na shape v0.2 (criterios/beneficios/fte_horas).
--
-- WRITE-ONLY MODE — aplicar MANUALMENTE no Supabase Cloud SQL Editor.
--   NÃO rodar `supabase db push` nem `supabase migration up`.
--   Handoff: .planning/phases/15-seed-dados-workshop/15-01-MIGRATION-HANDOFF.md
--
-- Pré-requisitos: 0001..0012 aplicadas (schema v0.2 completo: enums frequency_bucket
--   /fte_bucket, colunas criterios/beneficios/fte_horas/fonte, rpa_score GENERATED,
--   view opportunities_with_score, trigger seq_id, trigger handle_new_user).
--
-- IDEMPOTENTE: `on conflict` no tenant/user + GUARD POR COUNT no INSERT das 64
--   (D-06: se a Unidasul já tem oportunidades, pula o insert via raise notice —
--   seq_id é trigger-assigned, sem chave natural, então ON CONFLICT não protege).
--
-- NUNCA inserimos seq_id (trigger), rpa_score (GENERATED), score/priority_level
--   (view opportunities_with_score) — CLAUDE.md §3. Inserir aborta o statement.
-- =============================================================================

set session characteristics as transaction read write;
set default_transaction_read_only = off;

-- -----------------------------------------------------------------------------
-- 1. Tenant Unidasul (espelha 0002 §21-23) — UUID fixo próprio, distinto de
--    FGCoop (11111111-...) e do tenant de teste Acme (22222222-...).
-- -----------------------------------------------------------------------------
insert into tenants (id, name, slug)
values ('55551da5-0000-0000-0000-000000000001'::uuid, 'Unidasul', 'unidasul')
on conflict (slug) do nothing;

-- -----------------------------------------------------------------------------
-- 2. Auth user + identity do admin Unidasul (espelha 0002 §28-124).
--    UUID fixo próprio (bbbbbbbb-...), distinto do admin FGCoop (aaaaaaaa-...).
-- -----------------------------------------------------------------------------
do $$
declare
  v_user_id   uuid := 'bbbbbbbb-bbbb-bbbb-bbbb-bbbbbbbbbbbb'::uuid;
  v_tenant_id uuid := '55551da5-0000-0000-0000-000000000001'::uuid;
  v_email     text := 'admin.unidasul@pswdigital.com.br';
  v_password  text := '0123456789';
  v_full_name text := 'Admin Unidasul';
begin
  -- 2a. auth.users ----------------------------------------------------------
  -- handle_new_user trigger dispara e cria o profile a partir do tenant_id em
  -- raw_app_meta_data. email já confirmado (não precisa link).
  if not exists (select 1 from auth.users where id = v_user_id) then
    insert into auth.users (
      instance_id,
      id,
      aud,
      role,
      email,
      encrypted_password,
      email_confirmed_at,
      raw_app_meta_data,
      raw_user_meta_data,
      created_at,
      updated_at,
      confirmation_token,
      email_change,
      email_change_token_new,
      recovery_token
    ) values (
      '00000000-0000-0000-0000-000000000000'::uuid,
      v_user_id,
      'authenticated',
      'authenticated',
      v_email,
      crypt(v_password, gen_salt('bf')),
      now(),
      jsonb_build_object(
        'provider',  'email',
        'providers', jsonb_build_array('email'),
        'tenant_id', v_tenant_id::text           -- lido pelo trigger handle_new_user
      ),
      jsonb_build_object(
        'full_name', v_full_name,
        'tenant_id', v_tenant_id::text           -- redundância de segurança
      ),
      now(),
      now(),
      '',
      '',
      '',
      ''
    );
  end if;

  -- 2b. auth.identities -----------------------------------------------------
  -- Sem essa linha, login com email/senha falha em versões recentes do Supabase.
  if not exists (
    select 1 from auth.identities
    where provider = 'email' and user_id = v_user_id
  ) then
    insert into auth.identities (
      id,
      user_id,
      provider_id,
      identity_data,
      provider,
      last_sign_in_at,
      created_at,
      updated_at
    ) values (
      gen_random_uuid(),
      v_user_id,
      v_user_id::text,
      jsonb_build_object(
        'sub',            v_user_id::text,
        'email',          v_email,
        'email_verified', true,
        'phone_verified', false
      ),
      'email',
      now(),
      now(),
      now()
    );
  end if;

  -- 2c. profile (fallback caso o trigger não tenha rodado) + garante role.
  if not exists (select 1 from profiles where id = v_user_id) then
    insert into profiles (id, tenant_id, email, full_name, role)
    values (v_user_id, v_tenant_id, v_email, v_full_name, 'tenant_admin')
    on conflict (id) do nothing;
  else
    update profiles set role = 'tenant_admin'
    where id = v_user_id and role <> 'tenant_admin';
  end if;
end $$;

-- -----------------------------------------------------------------------------
-- 3. Sanity check (espelha 0003 §15-23): tenant e admin precisam existir.
-- -----------------------------------------------------------------------------
do $$
begin
  if not exists (select 1 from tenants where id = '55551da5-0000-0000-0000-000000000001'::uuid) then
    raise exception 'Tenant Unidasul não encontrado. Verifique o Bloco 1 desta migration.';
  end if;
  if not exists (select 1 from auth.users where id = 'bbbbbbbb-bbbb-bbbb-bbbb-bbbbbbbbbbbb'::uuid) then
    raise exception 'Admin Unidasul não encontrado. Verifique o Bloco 2 desta migration.';
  end if;
end $$;

-- -----------------------------------------------------------------------------
-- 4. Guard de idempotência por count (D-06) + INSERT das 64 oportunidades.
--    Colunas enumeradas como 0003. NÃO enumerar seq_id/rpa_score/score/
--    priority_level (trigger/GENERATED/view). criterios em sim/nao/parcial
--    (minúsculo, sem acento); beneficios 1–5; tempo=frequency_bucket; fte=fte_bucket.
